// ==================================================
// Split Line Items - يفرد المنتجات عشان نلوب عليهم
// ==================================================
const orderData = $('Parse Shopify Order1').first().json;
const lineItems = orderData.line_items || [];
const inputData = $input.first().json;
const partnerId = inputData.id;

return lineItems.map((item, index) => ({
  json: {
    index: index,
    partner_id: partnerId,
    sku: item.sku || '',
    title: item.title,
    variant_title: item.variant_title || '',
    quantity: item.quantity,
    price_unit: item.price,
    total_discount: item.total_discount || 0,
    shopify_product_id: item.shopify_product_id,
    shopify_variant_id: item.shopify_variant_id,
    _order_meta: index === 0 ? {
      shopify_order_id: orderData.shopify_order_id,
      shopify_order_name: orderData.shopify_order_name,
      shipping_method: orderData.shipping_method,
      shipping_cost: orderData.shipping_cost,
      payment: orderData.payment,
      totals: orderData.totals,
      note: orderData.note
    } : null
  }
}));

const order = $input.first().json.body || $input.first().json;
const customer = order.customer || {};
const shippingAddress = order.shipping_address || {};

const parsedOrder = {
  shopify_order_id: order.id,
  shopify_order_name: order.name,
  created_at: order.created_at,
  customer: {
    shopify_customer_id: customer.id || null,
    email: order.email || customer.email || '',
    full_name: ((customer.first_name || shippingAddress.first_name || '') + ' ' + 
                (customer.last_name || shippingAddress.last_name || '')).trim(),
    phone: customer.phone || shippingAddress.phone || order.phone || ''
  },
  shipping: {
    name: shippingAddress.name || '',
    address1: shippingAddress.address1 || '',
    address2: shippingAddress.address2 || '',
    city: shippingAddress.city || '',
    province: shippingAddress.province || '',
    country: shippingAddress.country || '',
    country_code: shippingAddress.country_code || '',
    zip: shippingAddress.zip || '',
    phone: shippingAddress.phone || ''
  },
  shipping_method: (order.shipping_lines && order.shipping_lines.length > 0) 
    ? order.shipping_lines[0].title : 'Standard Shipping',
  shipping_cost: (order.shipping_lines && order.shipping_lines.length > 0) 
    ? parseFloat(order.shipping_lines[0].price) : 0,
  payment: {
    financial_status: order.financial_status || 'pending',
    payment_gateway: order.payment_gateway_names 
      ? order.payment_gateway_names.join(', ') : '',
    currency: order.currency || 'USD'
  },
  totals: {
    subtotal: parseFloat(order.subtotal_price || 0),
    total: parseFloat(order.total_price || 0),
    total_tax: parseFloat(order.total_tax || 0),
    total_discounts: parseFloat(order.total_discounts || 0),
    discount_codes: order.discount_codes || []
  },
  line_items: (order.line_items || []).map(item => ({
    shopify_product_id: item.product_id,
    shopify_variant_id: item.variant_id,
    sku: item.sku || '',
    title: item.title || item.name || '',
    variant_title: item.variant_title || '',
    quantity: item.quantity || 1,
    price: parseFloat(item.price || 0),
    total_discount: parseFloat(item.total_discount || 0)
  })),
  note: order.note || '',
  tags: order.tags || ''
};

return [{ json: parsedOrder }];

const allSearchResults = $input.all();
const allSplitItems = $('Split Line Items').all();

const barcodeMap = {};
for (const result of allSearchResults) {
  if (result.json && result.json.barcode) {
    barcodeMap[result.json.barcode] = result.json;
  }
}

const results = [];
for (let i = 0; i < allSplitItems.length; i++) {
  const currentItem = allSplitItems[i].json;
  const matchedProduct = barcodeMap[currentItem.sku] || null;

  let productId = null;
  let productName = currentItem.title;

  if (matchedProduct && matchedProduct.id) {
    productId = matchedProduct.id;
    productName = matchedProduct.name || currentItem.title;
  }

  const unitPrice = currentItem.price_unit;
  const qty = currentItem.quantity;
  const totalDiscount = currentItem.total_discount || 0;
  const discountPercent = (qty > 0 && unitPrice > 0)
    ? (totalDiscount / (qty * unitPrice)) * 100
    : 0;

  results.push({
    json: {
      product_id: productId,
      product_name: productName,
      display_name: currentItem.variant_title
        ? currentItem.title + ' - ' + currentItem.variant_title
        : currentItem.title,
      quantity: currentItem.quantity,
      price_unit: currentItem.price_unit,
      discount: Math.round(discountPercent * 100) / 100,
      sku: currentItem.sku,
      partner_id: currentItem.partner_id,
      _order_meta: currentItem._order_meta
    }
  });
}
return results;

const allProducts = $input.all();
const partnerId = allProducts[0].json.partner_id;

let orderMeta = null;
for (const item of allProducts) {
  if (item.json._order_meta) {
    orderMeta = item.json._order_meta;
    break;
  }
}

const foundProducts = allProducts.filter(item => item.json.product_id !== null);
const notFoundProducts = allProducts.filter(item => item.json.product_id === null);

const orderLines = foundProducts.map(item => {
  return [
    0, 0, {
      product_id: item.json.product_id,
      name: item.json.display_name,
      product_uom_qty: item.json.quantity,
      price_unit: item.json.price_unit,
      discount: item.json.discount,
      tax_id: [[6, 0, []]]
    }
  ];
});

notFoundProducts.forEach(item => {
  orderLines.push([
    0, 0, {
      name: '[NOT FOUND] ' + item.json.display_name + ' (SKU: ' + item.json.sku + ')',
      product_uom_qty: item.json.quantity,
      price_unit: item.json.price_unit,
      discount: item.json.discount,
      tax_id: [[6, 0, []]]
    }
  ]);
});

return {
  json: {
    partner_id: partnerId,
    order_lines: orderLines,
    products_found: foundProducts.length,
    products_not_found: notFoundProducts.length,
    products_total: allProducts.length,
    order_meta: orderMeta
  }
};

const aggregatedData = $input.first().json;
const orderLines = aggregatedData.order_lines;
const partnerId = aggregatedData.partner_id;
const orderMeta = aggregatedData.order_meta || {};

const shippingCost = orderMeta.shipping_cost || 0;
if (shippingCost > 0) {
  orderLines.push([
    0, 0, {
      product_id: 16,
      name: 'مصاريف الشحن',
      product_uom_qty: 1,
      price_unit: shippingCost,
      discount: 0,
      tax_id: [[6, 0, []]]
    }
  ]);
}

const noteLines = [
  'Shopify Order: ' + (orderMeta.shopify_order_name || ''),
  'Shopify ID: ' + (orderMeta.shopify_order_id || ''),
  'Payment: ' + (orderMeta.payment ? orderMeta.payment.financial_status + ' (' + orderMeta.payment.payment_gateway + ')' : ''),
  'Shipping: ' + (orderMeta.shipping_method || ''),
  orderMeta.note ? 'Note: ' + orderMeta.note : ''
].filter(l => l).join('\n');

return {
  json: {
    partner_id: partnerId,
    order_line: orderLines,
    client_order_ref: 'Shopify ' + (orderMeta.shopify_order_name || ''),
    origin: 'Shopify ' + (orderMeta.shopify_order_name || ''),
    note: noteLines,
    source_id: 17,
    products_found: aggregatedData.products_found,
    products_not_found: aggregatedData.products_not_found
  }
};
